use cardano/transaction

pub type Datum {
  counter: Int,
}

validator increment_counter {
  spend(datum: Option<Datum>, _redeemer, own_ref, self) {
    expect Some(Datum { counter }) = datum
    let continuing = transaction.find_script_outputs(self.outputs, own_ref)
    expect Some(cont_output) = list.head(continuing)
    expect Some(raw) = transaction.find_datum(self.datums, cont_output.datum)
    expect Datum { counter: new_counter } = raw
    new_counter == counter + 1
  }
}

Checking `self.mint` is the authoritative source for what is being minted or burned in a transaction. Outputs can carry pre-existing tokens; inspecting them alone cannot distinguish newly minted tokens from tokens already in circulation.

```
use cardano/assets

validator token_policy {
  mint(_redeemer, policy_id, self) {
    // Only ever exactly 10 "Coin" tokens may be minted at once
    assets.quantity_of(self.mint, policy_id, "Coin") == 10
  }
}
```

Using `quantity_of` on `self.mint` directly reflects the net change for that policy in this transaction.

